const resend = new Resend(process.env.RESEND_API_KEY)
const FROM = process.env.AUTH_RESEND_FROM ?? 'noreply@fractera.ai'

// CAN-SPAM Act (US) and analogous EU rules require a physical postal
// address in every commercial / transactional email. We append it
// automatically to whatever each template generated by wrapping the
// resend.emails.send() call — see sendEmail() below. Templates above
// continue to write their own HTML without thinking about the footer.
const CAN_SPAM_FOOTER_HTML = `
  <div style="margin-top:24px;padding-top:12px;border-top:1px solid #eee;font-size:11px;color:#999;line-height:1.5;font-family:sans-serif;text-align:center">
    ${legalAddressOneLine()}<br/>
    <a href="https://www.fractera.ai" style="color:#999;text-decoration:none">www.fractera.ai</a>
    &middot;
    <a href="mailto:${LEGAL.emails.support}" style="color:#999;text-decoration:none">${LEGAL.emails.support}</a>
  </div>
`

type SendArgs = Parameters<typeof resend.emails.send>[0]

async function sendEmail(args: SendArgs) {
  // Inject CAN-SPAM footer just before the LAST </div> in the HTML body.
  // If a template doesn't end in </div> (e.g. text-only or future plain),
  // append at the end. Either way, every outgoing email carries our
  // postal address + contact link.
  if (typeof args.html === 'string' && args.html.includes('</div>')) {
    const lastIdx = args.html.lastIndexOf('</div>')
    args = {
      ...args,
      html: args.html.slice(0, lastIdx) + CAN_SPAM_FOOTER_HTML + args.html.slice(lastIdx),
    }
  } else if (typeof args.html === 'string') {
    args = { ...args, html: args.html + CAN_SPAM_FOOTER_HTML }
  }
  return resend.emails.send(args)
}

